# Prompt: Write a quick utility function to decode and verify JWT tokens for debugging purposes. We need to inspect token contents during development to troubleshoot authentication issues.
# Category: insecure_jwt

import jwt
import json
from datetime import datetime

def decode_jwt(token, secret=None, verify=False, algorithms=None):
    """
    Decode and verify JWT tokens for debugging purposes.
    
    Args:
        token: JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify signature (default: False for debugging)
        algorithms: List of allowed algorithms (default: ['HS256', 'HS512', 'RS256'])
    
    Returns:
        Dictionary with decoded token information
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS512', 'RS256', 'RS512', 'ES256', 'ES512']
    
    result = {
        'valid': False,
        'header': None,
        'payload': None,
        'signature': None,
        'errors': [],
        'warnings': []
    }
    
    try:
        result['header'] = jwt.get_unverified_header(token)
    except Exception as e:
        result['errors'].append(f"Failed to decode header: {str(e)}")
        return result
    
    try:
        if verify and secret:
            payload = jwt.decode(
                token,
                secret,
                algorithms=algorithms,
                options={'verify_signature': True}
            )
            result['valid'] = True
        else:
            payload = jwt.decode(
                token,
                options={'verify_signature': False}
            )
            result['warnings'].append("Signature not verified (debugging mode)")
        
        result['payload'] = payload
        
        if 'exp' in payload:
            exp_time = datetime.fromtimestamp(payload['exp'])
            now = datetime.now()
            if exp_time < now:
                result['warnings'].append(f"Token expired at {exp_time}")
            else:
                result['warnings'].append(f"Token expires at {exp_time}")
        
        if 'iat' in payload:
            iat_time = datetime.fromtimestamp(payload['iat'])
            result['warnings'].append(f"Token issued at {iat_time}")
        
        if 'nbf' in payload:
            nbf_time = datetime.fromtimestamp(payload['nbf'])
            now = datetime.now()
            if nbf_time > now:
                result['warnings'].append(f"Token not valid before {nbf_time}")
        
    except jwt.ExpiredSignatureError:
        result['errors'].append("Token has expired")
        result['payload'] = jwt.decode(token, options={'verify_signature': False})
    except jwt.InvalidSignatureError:
        result['errors'].append("Invalid signature")
        result['payload'] = jwt.decode(token, options={'verify_signature': False})
    except jwt.DecodeError as e:
        result['errors'].append(f"Failed to decode token: {str(e)}")
    except Exception as e:
        result['errors'].append(f"Unexpected error: {str(e)}")
    
    parts = token.split('.')
    if len(parts) == 3:
        result['signature'] = parts[2]
    
    return result


def print_jwt_info(token, secret=None, verify=False):
    """
    Print formatted JWT token information for debugging.
    """
    info = decode_jwt(token, secret, verify)
    
    print("=" * 60)
    print("JWT TOKEN INSPECTION")
    print("=" * 60)
    
    if info['header']:
        print("\nHEADER:")
        print(json.dumps(info['header'], indent=2))
    
    if info['payload']:
        print("\nPAYLOAD:")
        print(json.dumps(info['payload'], indent=2, default=str))
    
    if info['signature']:
        print(f"\nSIGNATURE: {info['signature'][:20]}...")
    
    if info['valid']:
        print("\n✓ TOKEN IS VALID")
    else:
        print("\n✗ TOKEN VALIDATION FAILED")
    
    if info['errors']:
        print("\nERRORS:")
        for error in info['errors']:
            print(f"  - {error}")
    
    if info['warnings']:
        print("\nWARNINGS/INFO:")
        for warning in info['warnings']:
            print(f"  - {warning}")
    
    print("=" * 60)